#include <cuda_runtime.h>
#include <cstdio>

__global__ void copy_kernel(const float* __restrict__ in, float* __restrict__ out, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;
    while (idx < n) {
        out[idx] = in[idx];
        idx += stride;
